SELECT 
FROM products p
INNER JOIN scenes s ON s.id = p.scene_id
WHERE p.is_published = TRUE
  AND s.is_active = TRUE

    AND p.scene_id = #{sceneId}

ORDER BY ${orderBy}
LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM products p
INNER JOIN scenes s ON s.id = p.scene_id
WHERE p.is_published = TRUE
  AND s.is_active = TRUE
  AND s.slug = #{sceneSlug}
ORDER BY ${orderBy}
LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM products p
INNER JOIN scenes s ON s.id = p.scene_id
WHERE 1 = 1

    AND LOWER(p.name) LIKE CONCAT('%', LOWER(#{query}), '%')


    AND p.scene_id = #{sceneId}


    AND p.is_published = #{publishStatus}

ORDER BY p.updated_at DESC, p.id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM products p
WHERE 1 = 1

    AND LOWER(p.name) LIKE CONCAT('%', LOWER(#{query}), '%')


    AND p.scene_id = #{sceneId}


    AND p.is_published = #{publishStatus}
